import React, { useRef, useEffect, useState } from 'react';
import Plyr from 'plyr';
import 'plyr/dist/plyr.css';
import { Play, Pause, Volume2, VolumeX, Maximize, Settings } from 'lucide-react';

const VideoPlayer = ({ video, onProgress, onComplete }) => {
  const videoRef = useRef(null);
  const playerRef = useRef(null);
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [volume, setVolume] = useState(1);
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    if (videoRef.current && !playerRef.current) {
      // Initialize Plyr
      playerRef.current = new Plyr(videoRef.current, {
        controls: [
          'play-large',
          'play',
          'progress',
          'current-time',
          'duration',
          'mute',
          'volume',
          'captions',
          'settings',
          'pip',
          'airplay',
          'fullscreen'
        ],
        settings: ['captions', 'quality', 'speed'],
        speed: { selected: 1, options: [0.5, 0.75, 1, 1.25, 1.5, 2] },
        quality: {
          default: 720,
          options: [4320, 2880, 2160, 1440, 1080, 720, 576, 480, 360, 240]
        },
        autoplay: false,
        muted: false,
        volume: 1,
        clickToPlay: true,
        hideControls: true,
        resetOnEnd: false,
        keyboard: { focused: true, global: false },
        tooltips: { controls: true, seek: true },
        captions: { active: false, language: 'auto', update: false },
        fullscreen: { enabled: true, fallback: true, iosNative: false },
        pip: { enabled: true },
        previewThumbnails: false,
        vimeo: { dnt: true },
        youtube: { noCookie: true, rel: 0, showinfo: 0, iv_load_policy: 3 }
      });

      // Event listeners
      playerRef.current.on('ready', () => {
        setDuration(playerRef.current.duration);
      });

      playerRef.current.on('play', () => {
        setIsPlaying(true);
      });

      playerRef.current.on('pause', () => {
        setIsPlaying(false);
      });

      playerRef.current.on('timeupdate', () => {
        const currentTime = playerRef.current.currentTime;
        setCurrentTime(currentTime);

        if (onProgress) {
          onProgress(currentTime);
        }
      });

      playerRef.current.on('ended', () => {
        if (onComplete) {
          onComplete();
        }
      });

      playerRef.current.on('volumechange', () => {
        setVolume(playerRef.current.volume);
        setIsMuted(playerRef.current.muted);
      });

      playerRef.current.on('enterfullscreen', () => {
        setIsFullscreen(true);
      });

      playerRef.current.on('exitfullscreen', () => {
        setIsFullscreen(false);
      });
    }

    return () => {
      if (playerRef.current) {
        playerRef.current.destroy();
        playerRef.current = null;
      }
    };
  }, [onProgress, onComplete]);

  useEffect(() => {
    if (playerRef.current && video) {
      // Update video source when video changes
      playerRef.current.source = {
        type: 'video',
        sources: [
          {
            src: video.processed_file || video.original_file,
            type: 'video/mp4',
            size: 720
          }
        ],
        poster: video.thumbnail
      };
    }
  }, [video]);

  const togglePlay = () => {
    if (playerRef.current) {
      if (isPlaying) {
        playerRef.current.pause();
      } else {
        playerRef.current.play();
      }
    }
  };

  const toggleMute = () => {
    if (playerRef.current) {
      playerRef.current.muted = !isMuted;
    }
  };

  const toggleFullscreen = () => {
    if (playerRef.current) {
      if (isFullscreen) {
        playerRef.current.exitFullscreen();
      } else {
        playerRef.current.enterFullscreen();
      }
    }
  };

  const handleVolumeChange = (e) => {
    const newVolume = parseFloat(e.target.value);
    if (playerRef.current) {
      playerRef.current.volume = newVolume;
    }
  };

  const formatTime = (seconds) => {
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);

    if (hours > 0) {
      return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
    return `${minutes}:${secs.toString().padStart(2, '0')}`;
  };

  if (!video) {
    return (
      <div className="w-full aspect-video bg-gray-900 flex items-center justify-center">
        <div className="text-white text-lg">No video available</div>
      </div>
    );
  }

  return (
    <div className="relative w-full aspect-video bg-black">
      {/* Video element */}
      <video
        ref={videoRef}
        className="w-full h-full"
        poster={video.thumbnail}
        playsInline
      >
        <source src={video.processed_file || video.original_file} type="video/mp4" />
        Your browser does not support the video tag.
      </video>

      {/* Custom controls overlay */}
      <div className="absolute inset-0 bg-gradient-to-t from-black/50 via-transparent to-transparent opacity-0 hover:opacity-100 transition-opacity duration-300">
        {/* Top controls */}
        <div className="absolute top-4 left-4 right-4 flex justify-between items-center">
          <div className="text-white text-sm font-medium">
            {video.title}
          </div>
          <button
            onClick={toggleFullscreen}
            className="p-2 rounded-lg bg-black/50 text-white hover:bg-black/70 transition-colors"
          >
            <Maximize className="h-4 w-4" />
          </button>
        </div>

        {/* Center play button */}
        <div className="absolute inset-0 flex items-center justify-center">
          <button
            onClick={togglePlay}
            className="p-4 rounded-full bg-black/50 text-white hover:bg-black/70 transition-colors"
          >
            {isPlaying ? (
              <Pause className="h-8 w-8" />
            ) : (
              <Play className="h-8 w-8 ml-1" />
            )}
          </button>
        </div>

        {/* Bottom controls */}
        <div className="absolute bottom-4 left-4 right-4">
          {/* Progress bar */}
          <div className="mb-2">
            <input
              type="range"
              min="0"
              max={duration}
              value={currentTime}
              onChange={(e) => {
                if (playerRef.current) {
                  playerRef.current.currentTime = parseFloat(e.target.value);
                }
              }}
              className="w-full h-1 bg-white/30 rounded-lg appearance-none cursor-pointer slider"
            />
          </div>

          {/* Control buttons */}
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-4">
              <button
                onClick={togglePlay}
                className="text-white hover:text-gray-300 transition-colors"
              >
                {isPlaying ? (
                  <Pause className="h-5 w-5" />
                ) : (
                  <Play className="h-5 w-5" />
                )}
              </button>

              <button
                onClick={toggleMute}
                className="text-white hover:text-gray-300 transition-colors"
              >
                {isMuted ? (
                  <VolumeX className="h-5 w-5" />
                ) : (
                  <Volume2 className="h-5 w-5" />
                )}
              </button>

              <div className="flex items-center space-x-2">
                <input
                  type="range"
                  min="0"
                  max="1"
                  step="0.1"
                  value={volume}
                  onChange={handleVolumeChange}
                  className="w-16 h-1 bg-white/30 rounded-lg appearance-none cursor-pointer slider"
                />
              </div>

              <div className="text-white text-sm">
                {formatTime(currentTime)} / {formatTime(duration)}
              </div>
            </div>

            <div className="flex items-center space-x-2">
              <button className="text-white hover:text-gray-300 transition-colors">
                <Settings className="h-5 w-5" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Loading indicator */}
      {!isPlaying && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-white"></div>
        </div>
      )}
    </div>
  );
};

export default VideoPlayer;
